// CustomerWithProducts DTO
package com.paymentchange.customer.dto;

import lombok.Data;
import java.util.List;

@Data
public class CustomerWithProducts {
    private Long id;
    private String name;
    private String phoneNumber;
    private List<Product> products; // Objetos completos, no IDs
}

// CustomerService - Método para obtener customer con productos
public CustomerWithProducts findByIdWithProducts(Long id) {
    // Buscar customer
    Customer customer = customerRepository.findById(id)
        .orElseThrow(() -> new RuntimeException("Customer no encontrado"));

    // Obtener productos completos
    List<Product> products = customer.getProductIds().stream()
        .map(productId -> webClient.get()
            .uri("/product/{id}", productId)
            .retrieve()
            .bodyToMono(Product.class)
            .block())
        .collect(Collectors.toList());

    // Crear DTO con datos completos
    CustomerWithProducts dto = new CustomerWithProducts();
    dto.setId(customer.getId());
    dto.setName(customer.getName());
    dto.setPhoneNumber(customer.getPhoneNumber());
    dto.setProducts(products);

    return dto;
}

