// Entidad Transaction
package com.paymentchange.transaction.entities;

import jakarta.persistence.*;
import lombok.Data;
import java.time.LocalDateTime;

@Data
@Entity
public class Transaction {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    private Long customerId; // Referencia a Customer
    private Long productId;  // Referencia a Product
    private Double amount;
    private LocalDateTime date;
    private String status; // PENDING, COMPLETED, FAILED
}

// TransactionService - Validaciones
@Service
public class TransactionService {

    @Autowired
    private WebClient customerWebClient;

    @Autowired
    private WebClient productWebClient;

    @Autowired
    private TransactionRepository repository;

    public Transaction create(Transaction transaction) {
        // Validar customer existe
        Customer customer = customerWebClient.get()
            .uri("/customer/{id}", transaction.getCustomerId())
            .retrieve()
            .bodyToMono(Customer.class)
            .block();

        if (customer == null) {
            throw new RuntimeException("Customer no encontrado");
        }

        // Validar producto existe
        Product product = productWebClient.get()
            .uri("/product/{id}", transaction.getProductId())
            .retrieve()
            .bodyToMono(Product.class)
            .block();

        if (product == null) {
            throw new RuntimeException("Producto no encontrado");
        }

        // Validar que customer tiene el producto
        if (!customer.getProductIds().contains(transaction.getProductId())) {
            throw new RuntimeException("Customer no posee este producto");
        }

        // Persistir transacción
        transaction.setDate(LocalDateTime.now());
        transaction.setStatus("COMPLETED");
        return repository.save(transaction);
    }
}

